module RefModule (
    input [7:0] data_in,
    output reg [7:0] checksum_out
);
    integer obf_i;
    reg [7:0] sum;

    always @(*) begin
        sum = 8'b0;
        for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
            sum = sum + data_in[obf_i];
        end
        checksum_out = sum % 256;
    end
endmodule
